    fun isLand(x: Int, y: Int): Boolean {
        if (x < 0 || x >= GRID_W || y < 0 || y >= GRID_H) return false
        val byteIndex = y * BYTES_PER_ROW + (x / 8)
        val bitIndex = x % 8
        return ((bitmap[byteIndex].toInt() shr bitIndex) and 1) == 1
    }
